import React from 'react';
import { useNavigate } from 'react-router-dom';
import VideoBackground from "../VideoBackground/VideoBackground";
import './ProfessorPage.css'; // Vom crea acest CSS

const ProfessorPage: React.FC = () => {
    const username = localStorage.getItem('username') || 'Profesor';
    const navigate = useNavigate();

    const handleCreateClick = () => {
        navigate('/create-assignment'); // Redirecționare
    };

    return (
        <div className="professor-page-container">
            <VideoBackground />
            <div className="Patrat_stanga">
                <div className="dashboard-card card-welcome">
                    <h2>Bine ai venit, {username}!</h2>

                </div>
            </div>

            <div className="dashboard-grid">

                
                <p>Selectează o acțiune pentru a începe.</p>
                <button onClick={handleCreateClick} className="card-button">
                    Creează o Temă Nouă
                </button>


                {/* === Chenarul 2 (Mijloc) === */}
                <div className="dashboard-card card-stats">
                    <h3>Statistică</h3>
                    <p>Aici vor apărea temele trimise vs. cele necorectate.</p>
                    {/* (Conținut viitor) */}
                </div>

                {/* === Chenarul 3 (Dreapta) === */}
                <div className="dashboard-card card-activity">
                    <h3>Activitate Recentă</h3>
                    <p>Aici va apărea un feed cu ultimele teme încărcate.</p>
                    {/* (Conținut viitor) */}
                </div>

            </div>
        </div>
    );
};

export default ProfessorPage;
